mapper.select:
SELECT o.id, o.product_id, o.buyer_id, o.seller_id, o.status,
       o.cancelled_by, o.idempotent_key, o.product_snapshot,
       o.met_at, o.confirmed_at, o.created_at, o.updated_at
FROM orders o


    AND o.buyer_id = #{userId}
    AND o.seller_id = #{userId}
    AND (o.buyer_id = #{userId} OR o.seller_id = #{userId})


    AND o.status = #{status}


ORDER BY o.updated_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM orders o


    AND o.buyer_id = #{userId}
    AND o.seller_id = #{userId}
    AND (o.buyer_id = #{userId} OR o.seller_id = #{userId})


    AND o.status = #{status}
